    50→namespace sofa {
    51→namespace pbrpc {
    52→
    53→static const int kDefaultBufferSize = 65536;
    54→
    55→GzipInputStream::GzipInputStream(
    56→    ZeroCopyInputStream* sub_stream, Format format, int buffer_size)
    57→    : format_(format), sub_stream_(sub_stream), zerror_(Z_OK) {
    58→  zcontext_.next_in = NULL;
    59→  zcontext_.avail_in = 0;
    60→  zcontext_.total_in = 0;
    61→  zcontext_.next_out = NULL;
    62→  zcontext_.avail_out = 0;
    63→  zcontext_.total_out = 0;
    64→  zcontext_.msg = NULL;
    65→  zcontext_.state = NULL;
    66→  zcontext_.zalloc = Z_NULL;
    67→  zcontext_.zfree = Z_NULL;
    68→  zcontext_.opaque = Z_NULL;
    69→  zcontext_.total_out = 0;
    70→  zcontext_.data_type = Z_BINARY;
    71→  zcontext_.adler = 0;
    72→  zcontext_.reserved = 0;
    73→  if (buffer_size == -1) {
    74→    output_buffer_length_ = kDefaultBufferSize;
    75→  } else {
    76→    output_buffer_length_ = buffer_size;
    77→  }
    78→  output_buffer_ = operator new(output_buffer_length_);
    79→  GOOGLE_CHECK(output_buffer_ != NULL);
    80→  zcontext_.next_out = static_cast<Bytef*>(output_buffer_);
    81→  zcontext_.avail_out = output_buffer_length_;
    82→  output_position_ = output_buffer_;
    83→}
    84→
    85→GzipInputStream::~GzipInputStream() {
    86→  operator delete(output_buffer_);
    87→  // Back up input stream if there are unused bytes
    88→  if (ExpectAtEnd() && zcontext_.avail_in > 0) {
    89→    sub_stream_->BackUp(zcontext_.avail_in);
    90→    zcontext_.avail_in = 0;
    91→  }
    92→  zerror_ = inflateEnd(&zcontext_);
    93→}
    94→
    95→static inline int internalInflateInit2(
    96→    z_stream* zcontext, GzipInputStream::Format format) {
    97→  int windowBitsFormat = 0;
    98→  switch (format) {
    99→    case GzipInputStream::GZIP: windowBitsFormat = 16; break;
   100→    case GzipInputStream::AUTO: windowBitsFormat = 32; break;
   101→    case GzipInputStream::ZLIB: windowBitsFormat = 0; break;
   102→  }
   103→  return inflateInit2(zcontext, /* windowBits */15 | windowBitsFormat);
   104→}
   105→
   106→int GzipInputStream::Inflate(int flush) {
   107→  if ((zerror_ == Z_OK) && (zcontext_.avail_out == 0)) {
   108→    // previous inflate filled output buffer. don't change input params yet.
   109→  } else if (zcontext_.avail_in == 0) {
   110→    const void* in;
   111→    int in_size;
   112→    bool first = zcontext_.next_in == NULL;
   113→    bool ok = sub_stream_->Next(&in, &in_size);
   114→    if (!ok) {
   115→      zcontext_.next_out = NULL;
   116→      zcontext_.avail_out = 0;
   117→      return Z_STREAM_END;
   118→    }
   119→    zcontext_.next_in = static_cast<Bytef*>(const_cast<void*>(in));
   120→
   121→    zcontext_.avail_in = in_size;
   122→    if (first) {
   123→      int error = internalInflateInit2(&zcontext_, format_);
   124→      if (error != Z_OK) {
   125→        return error;
   126→      }
   127→    }
   128→  }
   129→  zcontext_.next_out = static_cast<Bytef*>(output_buffer_);
   130→  zcontext_.avail_out = output_buffer_length_;
   131→  output_position_ = output_buffer_;
   132→  int error = inflate(&zcontext_, flush);
   133→  return error;
   134→}
   135→
   136→void GzipInputStream::DoNextOutput(const void** data, int* size) {
   137→  *data = output_position_;
   138→  *size = ((uintptr_t)zcontext_.next_out) - ((uintptr_t)output_position_);
   139→  output_position_ = zcontext_.next_out;
   140→}
   141→
   142→// implements ZeroCopyInputStream ----------------------------------
   143→bool GzipInputStream::Next(const void** data, int* size) {
   144→  bool ok = (zerror_ == Z_OK) || (zerror_ == Z_STREAM_END)
   145→      || (zerror_ == Z_BUF_ERROR);
   146→  if ((!ok) || (zcontext_.next_out == NULL)) {
   147→    return false;
   148→  }
   149→  if (zcontext_.next_out != output_position_) {
   150→    DoNextOutput(data, size);
   151→    return true;
   152→  }
   153→  if (zerror_ == Z_STREAM_END) {
   154→    // First backup stream
   155→    if (zcontext_.avail_in) {
   156→      sub_stream_->BackUp(zcontext_.avail_in);
   157→    }
   158→    if (zcontext_.next_out != NULL) {
   159→      // sub_stream_ may have concatenated streams to follow
   160→      zerror_ = inflateEnd(&zcontext_);
   161→      if (zerror_ != Z_OK) {
   162→        return false;
   163→      }
   164→      zerror_ = internalInflateInit2(&zcontext_, format_);
   165→      if (zerror_ != Z_OK) {
   166→        return false;
   167→      }
   168→    } else {
   169→      *data = NULL;
   170→      *size = 0;
   171→      return false;
   172→    }
   173→  }
   174→  zerror_ = Inflate(Z_NO_FLUSH);
   175→  if ((zerror_ == Z_STREAM_END) && (zcontext_.next_out == NULL)) {
   176→    // The underlying stream's Next returned false inside Inflate.
   177→    return false;
   178→  }
   179→  ok = (zerror_ == Z_OK) || (zerror_ == Z_STREAM_END)
   180→      || (zerror_ == Z_BUF_ERROR);
   181→  if (!ok) {
   182→    return false;
   183→  }
   184→  DoNextOutput(data, size);
   185→  return true;
   186→}
   187→
   188→bool GzipInputStream::ExpectAtEnd() {
   189→  if (zerror_ == Z_STREAM_END) return true;
   190→  bool ok = (zerror_ == Z_OK) || (zerror_ == Z_BUF_ERROR);
   191→  if (!ok) {
   192→    return false;
   193→  }
   194→  const void* data;
   195→  int size = 0;
   196→  while (size == 0) {
   197→    bool ok = Next(&data, &size);
   198→    if (zerror_ == Z_STREAM_END) return true;
   199→    if (!ok) {
   200→      return false;
   201→    }
   202→  }
   203→  BackUp(size);
   204→  return false;
   205→}
   206→
   207→void GzipInputStream::BackUp(int count) {
   208→  output_position_ = reinterpret_cast<void*>(
   209→      reinterpret_cast<uintptr_t>(output_position_) - count);
   210→}
   211→
   212→bool GzipInputStream::Skip(int count) {
   213→  const void* data;
   214→  int size;
   215→  bool ok = Next(&data, &size);
   216→  while (ok && (size < count)) {
   217→    count -= size;
   218→    ok = Next(&data, &size);
   219→  }
   220→  if (size > count) {
   221→    BackUp(size - count);
   222→  }
   223→  return ok;
   224→}
   225→
   226→int64 GzipInputStream::ByteCount() const {
   227→  return zcontext_.total_out +
   228→    (((uintptr_t)zcontext_.next_out) - ((uintptr_t)output_position_));
   229→}
   230→
   231→// =========================================================================
   232→
   233→GzipOutputStream::Options::Options()
   234→    : format(GZIP),
   235→      buffer_size(kDefaultBufferSize),
   236→      compression_level(Z_DEFAULT_COMPRESSION),
   237→      compression_strategy(Z_DEFAULT_STRATEGY) {}
   238→
   239→GzipOutputStream::GzipOutputStream(ZeroCopyOutputStream* sub_stream) {
   240→  Init(sub_stream, Options());
   241→}
   242→
   243→GzipOutputStream::GzipOutputStream(ZeroCopyOutputStream* sub_stream,
   244→                                   const Options& options) {
   245→  Init(sub_stream, options);
   246→}
   247→
   248→GzipOutputStream::GzipOutputStream(
   249→    ZeroCopyOutputStream* sub_stream, Format format, int buffer_size) {
   250→  Options options;
   251→  options.format = format;
   252→  if (buffer_size != -1) {
   253→    options.buffer_size = buffer_size;
   254→  }
   255→  Init(sub_stream, options);
   256→}
   257→
   258→void GzipOutputStream::Init(ZeroCopyOutputStream* sub_stream,
   259→                            const Options& options) {
   260→  sub_stream_ = sub_stream;
   261→  sub_data_ = NULL;
   262→  sub_data_size_ = 0;
   263→
   264→  input_buffer_length_ = options.buffer_size;
   265→  input_buffer_ = operator new(input_buffer_length_);
   266→  GOOGLE_CHECK(input_buffer_ != NULL);
   267→
   268→  zcontext_.zalloc = Z_NULL;
   269→  zcontext_.zfree = Z_NULL;
   270→  zcontext_.opaque = Z_NULL;
   271→  zcontext_.next_out = NULL;
   272→  zcontext_.avail_out = 0;
   273→  zcontext_.total_out = 0;
   274→  zcontext_.next_in = NULL;
   275→  zcontext_.avail_in = 0;
   276→  zcontext_.total_in = 0;
   277→  zcontext_.msg = NULL;
   278→  // default to GZIP format
   279→  int windowBitsFormat = 16;
   280→  if (options.format == ZLIB) {
   281→    windowBitsFormat = 0;
   282→  }
   283→  zerror_ = deflateInit2(
   284→      &zcontext_,
   285→      options.compression_level,
   286→      Z_DEFLATED,
   287→      /* windowBits */15 | windowBitsFormat,
   288→      /* memLevel (default) */8,
   289→      options.compression_strategy);
   290→}
   291→
   292→GzipOutputStream::~GzipOutputStream() {
   293→  Close();
   294→  if (input_buffer_ != NULL) {
   295→    operator delete(input_buffer_);
   296→  }
   297→}
   298→
   299→// private
   300→int GzipOutputStream::Deflate(int flush) {
   301→  int error = Z_OK;
   302→  do {
   303→    if ((sub_data_ == NULL) || (zcontext_.avail_out == 0)) {
   304→      bool ok = sub_stream_->Next(&sub_data_, &sub_data_size_);
   305→      if (!ok) {
   306→        sub_data_ = NULL;
   307→        sub_data_size_ = 0;
   308→        return Z_BUF_ERROR;
   309→      }
   310→      GOOGLE_CHECK_GT(sub_data_size_, 0);
   311→      zcontext_.next_out = static_cast<Bytef*>(sub_data_);
   312→      zcontext_.avail_out = sub_data_size_;
   313→    }
   314→    error = deflate(&zcontext_, flush);
   315→  } while (error == Z_OK && zcontext_.avail_out == 0);
   316→  if ((flush == Z_FULL_FLUSH) || (flush == Z_FINISH)) {
   317→    // Notify lower layer of data.
   318→    sub_stream_->BackUp(zcontext_.avail_out);
   319→    // We don't own the buffer anymore.
   320→    sub_data_ = NULL;
   321→    sub_data_size_ = 0;
   322→  }
   323→  return error;
   324→}
   325→
   326→// implements ZeroCopyOutputStream ---------------------------------
   327→bool GzipOutputStream::Next(void** data, int* size) {
   328→  if ((zerror_ != Z_OK) && (zerror_ != Z_BUF_ERROR)) {
   329→    return false;
   330→  }
   331→  if (zcontext_.avail_in != 0) {
   332→    zerror_ = Deflate(Z_NO_FLUSH);
   333→    if (zerror_ != Z_OK) {
   334→      return false;
   335→    }
   336→  }
   337→  if (zcontext_.avail_in == 0) {
   338→    // all input was consumed. reset the buffer.
   339→    zcontext_.next_in = static_cast<Bytef*>(input_buffer_);
   340→    zcontext_.avail_in = input_buffer_length_;
   341→    *data = input_buffer_;
   342→    *size = input_buffer_length_;
   343→  } else {
   344→    // The loop in Deflate should consume all avail_in
   345→    GOOGLE_LOG(DFATAL) << "Deflate left bytes unconsumed";
   346→  }
   347→  return true;
   348→}
   349→void GzipOutputStream::BackUp(int count) {
   350→  GOOGLE_CHECK_GE(int(zcontext_.avail_in), count);
   351→  zcontext_.avail_in -= count;
   352→}
   353→int64 GzipOutputStream::ByteCount() const {
   354→  return zcontext_.total_in + zcontext_.avail_in;
   355→}
   356→
   357→bool GzipOutputStream::Flush() {
   358→  do {
   359→    zerror_ = Deflate(Z_FULL_FLUSH);
   360→  } while (zerror_ == Z_OK);
   361→  return zerror_ == Z_OK;
   362→}
   363→
   364→bool GzipOutputStream::Close() {
   365→  if ((zerror_ != Z_OK) && (zerror_ != Z_BUF_ERROR)) {
   366→    return false;
   367→  }
   368→  do {
   369→    zerror_ = Deflate(Z_FINISH);
   370→  } while (zerror_ == Z_OK);
   371→  zerror_ = deflateEnd(&zcontext_);
   372→  bool ok = zerror_ == Z_OK;
   373→  zerror_ = Z_STREAM_END;
   374→  return ok;
   375→}
